var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그러니까...... 여기서 혼자 20년을 버텨 왔다고?","JPN":"だから……ここで一人で20年も耐えてきたの？","ENG":"So you're saying... you survived alone here for 20 years?","TWN":"所以說……妳一個人在這裡待了20年？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"20년?","JPN":"20年……？","ENG":"20 years?","TWN":"20年？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"시간이...... 벌써 그렇게 흘렀나?","JPN":"もう……そんなに時が経ったのか？","ENG":"Has it been that long already?","TWN":"已經過了……這麼長的時間了？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"실감이 나지 않아. 날짜를 세는 건 오래 전에 포기했거든.","JPN":"実感が湧かないな。\\n日にちを数えるのも、とうの昔にやめていたものでね。","ENG":"It hardly feels like it's been that long. I gave up on keeping count of the days a long time ago.","TWN":"真沒有實感，我很早就放棄計算日期了。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래도 굉장하군. 쉬운 일은 아니었을 텐데.","JPN":"それにしてもすごいな。生半可なことではなかっただろう。","ENG":"Still, it's very impressive. It couldn't have been easy.","TWN":"但這仍舊很厲害，真是不簡單。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"어째서 도망치지 않았나?","JPN":"なぜ逃げ出さなかったんだ？","ENG":"Why didn't you run?","TWN":"妳為什麼沒逃跑？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그게 더 현명한 판단이었을지도 모르지.","JPN":"その方が賢明だったかもしれないな。","ENG":"Perhaps that would have been the prudent thing to do.","TWN":"或許那才是明智的判斷。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"하지만 도플갱어들이 대원들을 노리고 있는데 나 혼자 떠날 수는 없었다.","JPN":"しかし、隊員たちがドッペルゲンガーに狙われているときに\\n私一人だけで離脱することはできなかった。","ENG":"But I could not leave my troops behind, not when the Doppelgangers were after them.","TWN":"但二重身們對我的隊員虎視眈眈，我不能丟下他們不管。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"다행히 이 근처엔 쓸 만한 물건이 많았어.","JPN":"幸い、この辺りには使えそうな物が多かった。","ENG":"Fortunately, there was plenty of useful stuff around here.","TWN":"幸虧附近有很多有用的東西。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"버려진 함선에 무기와 보급품이 실려 있었으니까.","JPN":"打ち捨てられた艦船には、武器や補給品も積んであったからな。","ENG":"The abandoned ships were loaded with weaponry and supplies.","TWN":"廢棄的艦船上裝載著武器和補給品。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"특히 기갑 병기들이 유용했다. 관제사를 지망하던 시절 정비 기술을 배웠거든.","JPN":"機甲兵器は特に役に立ってくれた。管制官を\\n志していた頃に整備技術を習っておいたおかげでな。","ENG":"The armored vehicles were particularly useful. When I was a prospective air traffic controller, I also learned how to perform maintenance.","TWN":"尤其是機械兵器非常有用。我以前志願成為管制員的時候，曾經學過整備技術。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그러고 보니......","JPN":"そういえば……","ENG":"Oh... Come to think of it...","TWN":"話說回來……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CANNON_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"오는 도중 공격해 왔던 기갑 병기들의 인공지능에 누군가가 조작한 흔적이 있었지.","JPN":"途中で攻撃してきた機甲兵器類の人工知能に、\\n何者かによる操作の痕跡があったな。","ENG":"I did notice someone tampered with the A.I. of the armored vehicles that attacked us on the way here.","TWN":"在路上攻擊我們的機械兵器，上面的人工智慧留有被人操作的痕跡。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CANNON_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이제 보니 자네가 한 일이었군.","JPN":"あれは君の手によるものだったか。","ENG":"So that was your doing.","TWN":"原來那是妳做的。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CANNON_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"정보 오염이 심각하게 진행된 기체들을 제외하면 말이지.","JPN":"情報汚染が深刻に進んだ機体を除けばそのとおりだ。","ENG":"Except the ones that had their data corrupted beyond repair.","TWN":"除了資訊污染極其嚴重的機體以外。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"이 곳에서 달리 아군을 구할 수는 없었으니까.","JPN":"ここでは他に味方を募ることもできなかったからな。","ENG":"There was no other way to secure allies around here.","TWN":"因為我在這裡沒辦法找到其他友軍。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"하지만 너희들까지 공격에 휘말렸다니 마무리가 조금 서툴렀나 보군. 미안하다.","JPN":"だが、お前たちまで攻撃に巻き込まれていたとは……\\n仕上げが少々粗かったのかもしれん。すまない。","ENG":"But I suppose the calibrations could use a little more work since they attacked you as well. Sorry about that.","TWN":"但沒想到連你們也被它們攻擊了，看來是我搞砸了，抱歉。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"괜찮아. 네 손재주가 괴멸적인 건 예전부터 알고 있었으니까.","JPN":"いいのよ。あなたの手先が壊滅的に不器用なのはよく知ってるもの。","ENG":"It's fine. I always knew you had a rather destructive touch.","TWN":"沒關係，我從以前就知道妳的手藝是毀滅性的。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그 곰인형도 그렇잖아.","JPN":"そのクマのぬいぐるみだってそうでしょ？","ENG":"Like that teddy bear, for instance.","TWN":"那個小熊玩偶也是。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"너야말로 여전히 보는 눈이 없군. 이건 솔개라고 하지 않았나.","JPN":"そういうお前の目は相変わらず節穴だな。\\nこれはトンビだと何度も言ったはずだ。","ENG":"And you've always had no eye for talent. I told you this is a hawk.","TWN":"妳才是依舊沒什麼眼光，我說過這是黑鳶。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"......그 말을 듣고 나니 나도 이번에는 부사장의 안목이 맞는 것 같은데.","JPN":"……それを聞いたら私も副社長の見解に同意せざるを得ないが。","ENG":"I'm going to have to agree with the Vice President on this one.","TWN":"……聽妳這麼說，我覺得這次副總的眼光是對的。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그나저나 믿기지 않는군.","JPN":"しかし、今なお信じがたい。","ENG":"In any case, it's remarkable.","TWN":"不過真是不敢相信。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"온갖 수를 써도 실패했건만, 어떻게 방주의 동결을 해제한 거지?","JPN":"私はあらゆる手を尽くして失敗したのに、\\nどうやって箱舟の凍結を解除できたのだ？","ENG":"I've tried everything and nothing worked. How did you undo the stasis on the Ark?","TWN":"我用了無數的方法全都失敗了，但你們是怎麼解除方舟的凍結？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"덕분에 내 기다림이 헛되지 않게 됐어.","JPN":"おかげで今まで待っていたのが無駄にならずに済んだ。","ENG":"Looks like my patience was not in vain after all.","TWN":"多虧了你們，我的等待才沒有白費。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"네가 지원해 주러 와서 다행이다, 이수연. 역시 관리국의 에이스라고 불릴 만해.","JPN":"お前が支援に来てくれて幸いだ、カナミ。\\nやはり管理局のエースと呼ばれるだけのことはあるな。","ENG":"I'm glad you came to support me, Sooyeon. You are indeed the ace up the Administration's sleeve.","TWN":"有妳來支援真是太好了，李秀妍。妳果然是管理局的王牌。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"과찬이야. 이 정도는 간단하지.","JPN":"褒めすぎよ。これくらい簡単だわ。","ENG":"You flatter me. This was a walk in the park, really.","TWN":"過獎了，舉手之勞而已。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L42_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"크흠! 자랑할 생각은 없지만 동결을 해제한 건 내 덕분 아니었나?","JPN":"おっほん！　自慢するつもりはないが、凍結を\\n解除したのは私のおかげではなかったかね？","ENG":"Ahem! I don't mean to brag, but wasn't I the one who removed the stasis?","TWN":"咳咳！雖然不是我想炫耀，但解除凍結不是我的功勞嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......공치사를 좋아하시는 줄은 몰랐군요.","JPN":"……恩着せがましい上司は嫌われますよ。","ENG":"I didn't know you loved to take credit so much.","TWN":"……我沒想到您這麼喜歡施恩圖報呢。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L44_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그래, 이수연의 동료라고 했지.","JPN":"そうか、カナミの同僚だと言っていたな。","ENG":"Right. You said you were a colleague of Sooyeon.","TWN":"對了，你是李秀妍的同事吧。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"험난한 곳까지 와 줘서 정말 고맙다. 덕분에 내 기다림은 헛되지 않았어.","JPN":"こんな危険な場所にまで来てくれたことに感謝する。\\nおかげで長い苦労が報われた。","ENG":"I appreciate you accompanying her to such an austere environment. Thanks to you, my patience was not in vain.","TWN":"真的很謝謝你願意來到這麼危險的地方。多虧有你，才沒有讓我的等待白費。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L47_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"보게, 부사장. 사람은 순수하게 감사를 표할 줄도 알아야 하는 거야.","JPN":"見ろ、副社長。人はこんな風に素直に感謝を示すことが大事だぞ。","ENG":"See, Vice President? Sometimes people need to know how to say a simple thank you.","TWN":"看，副總，人應該要懂得真誠地表達感謝。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L48_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L49_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그런데 사이가 무척 돈독해 보이는군. 서로 사귀는 사이인가?","JPN":"しかし、とても親しい仲のようだな。二人は交際しているのか？","ENG":"By the way, you two seem pretty well acquainted. Are you perhaps in an intimate relationship?","TWN":"話說回來，你們兩個看起來很親密，是在交往嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L50_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"무, 뭣?! 아, 아니, 지금 무슨 소릴......!","JPN":"なっ、何ですって！？　ちょ、ちょっと、急に何てことを……！","ENG":"W-what? D-don't be ridiculous!","TWN":"什、什麼？！妳、妳在，說什麼……！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하하, 그렇게 보이나? 실은......","JPN":"ハハ、そう見えるか？　実は……","ENG":"Hah hah, do we look like a couple? Well, to be honest—","TWN":"哈哈，我們像戀人嗎？其實……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"뭐지? 이 소리는?","JPN":"この音は……？","ENG":"Huh? What's that sound?","TWN":"嗯？這個聲音是？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L5_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"음. 아무래도 또 쳐들어올 때가 됐나 보군.","JPN":"うむ。どうやらまた襲撃のようだ。","ENG":"Hmm... They must be coming again.","TWN":"嗯，看來是那些傢伙又殺過來了。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L6_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"누가? 그 도플갱어들인가?","JPN":"襲撃？　あのドッペルゲンガーたちが？","ENG":"Who? The Doppelgangers?","TWN":"誰？是那些二重身嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"아니. 방주를 노리는 적은 그 녀석들만이 아니다.","JPN":"いや、箱舟を狙う敵はそいつらだけではない。","ENG":"No. They are not the only ones after the Ark.","TWN":"不，想對方舟下手的不僅僅是它們。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"어찌됐든 이곳도 이면세계야.","JPN":"何しろここは裏世界だ。","ENG":"This is the Counterside, after all.","TWN":"不管怎麼說，這裡也是異界。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"주위를 배회하는 침식체 군집들이 주기적으로 습격해 오곤 하지.","JPN":"周辺を徘徊している侵食体の群集が\\n周期的に襲撃をかけてきている。","ENG":"Clusters of C.O.s in the vicinity attack periodically.","TWN":"在附近徘徊的侵蝕體群，它們會定期地發動襲擊。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"여기서 기다려라. 처리하고 오겠다.","JPN":"ここで待っていてくれ。私は連中を片付けてくる。","ENG":"Wait here. I'll go take care of them.","TWN":"你們在這裡等一下，我去處理它們。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};